const express = require('express');
const multer = require('multer');
const sharp = require('sharp');
const path = require('path');
const fs = require('fs');

const router = express.Router();

const UPLOAD_ROOT = path.join(process.cwd(), 'public', 'uploads');
const THUMB_SUFFIX = '_thumb';
const THUMB_WIDTH = 256;

const ALLOWED_EXT = new Set(['.jpg', '.jpeg', '.png', '.gif', '.svg', '.pdf', '.doc', '.docx', '.zip']);
const IMAGE_EXT = new Set(['.jpg', '.jpeg', '.png', '.gif', '.svg']);

function ensureDir(p) {
  fs.mkdirSync(p, { recursive: true });
}

function safeBasename(name) {
  return String(name || '')
    .replace(/[/\\?%*:|"<>]/g, '_')
    .replace(/\s+/g, '_')
    .slice(0, 180) || 'file';
}

function isEnterprise(req) {
  const user = req.user || {};
  return Boolean(user.enterprise === true || user.plan === 'enterprise' || user.tier === 'enterprise' || user.accountType === 'enterprise');
}

function getUploadCategory(req) {
  const t = String(req.body.type || req.query.type || '').toLowerCase();
  if (t === 'avatar' || t === 'avatars') return 'avatars';
  if (t === 'document' || t === 'documents' || t === 'doc' || t === 'docs') return 'documents';
  return 'files';
}

function uniqueFilename(originalname) {
  const ext = path.extname(originalname || '').toLowerCase();
  const base = safeBasename(path.basename(originalname || 'file', ext));
  const stamp = Date.now().toString(36);
  const rand = Math.random().toString(36).slice(2, 10);
  return `${base}-${stamp}-${rand}${ext || ''}`;
}

const storage = multer.diskStorage({
  destination: (req, file, cb) => {
    const category = getUploadCategory(req);
    const dest = path.join(UPLOAD_ROOT, category);
    ensureDir(dest);
    cb(null, dest);
  },
  filename: (req, file, cb) => {
    cb(null, uniqueFilename(file.originalname));
  }
});

function fileFilter(req, file, cb) {
  const ext = path.extname(file.originalname || '').toLowerCase();
  if (!ALLOWED_EXT.has(ext)) {
    const err = new Error('Unsupported file type');
    err.code = 'UNSUPPORTED_FILE_TYPE';
    return cb(err);
  }
  cb(null, true);
}

function buildMulter(req) {
  const enterprise = isEnterprise(req);
  const limits = enterprise ? {} : { fileSize: 10 * 1024 * 1024 }; // 10MB default cap for non-enterprise
  return multer({ storage, fileFilter, limits });
}

async function createThumbnailIfImage(filePath) {
  const ext = path.extname(filePath).toLowerCase();
  if (!IMAGE_EXT.has(ext)) return null;

  const dir = path.dirname(filePath);
  const name = path.basename(filePath, ext);
  const thumbExt = ext === '.svg' ? '.png' : ext;
  const thumbName = `${name}${THUMB_SUFFIX}${thumbExt}`;
  const thumbPath = path.join(dir, thumbName);

  try {
    if (ext === '.svg') {
      await sharp(filePath, { density: 300 })
        .resize({ width: THUMB_WIDTH, withoutEnlargement: true })
        .png()
        .toFile(thumbPath);
    } else if (ext === '.gif') {
      await sharp(filePath, { animated: true })
        .resize({ width: THUMB_WIDTH, withoutEnlargement: true })
        .toFile(thumbPath);
    } else {
      await sharp(filePath)
        .resize({ width: THUMB_WIDTH, withoutEnlargement: true })
        .toFile(thumbPath);
    }
    return thumbPath;
  } catch {
    return null;
  }
}

router.post('/upload', (req, res, next) => {
  const upload = buildMulter(req).single('file');
  upload(req, res, async (err) => {
    if (err) return next(err);
    if (!req.file) return res.status(400).json({ error: 'No file uploaded' });

    const category = getUploadCategory(req);
    const relDir = `/uploads/${category}`;
    const fileUrl = `${relDir}/${req.file.filename}`;

    const thumbPath = await createThumbnailIfImage(req.file.path);
    let thumbUrl = null;
    if (thumbPath) {
      const thumbName = path.basename(thumbPath);
      thumbUrl = `${relDir}/${thumbName}`;
    }

    res.json({
      ok: true,
      type: category,
      field: req.file.fieldname,
      originalName: req.file.originalname,
      filename: req.file.filename,
      size: req.file.size,
      mimetype: req.file.mimetype,
      url: fileUrl,
      thumbnailUrl: thumbUrl
    });
  });
});

module.exports = router;